1	interface QuoteItem {
2	  type: string;
3	  damage: number;
4	  cursed?: boolean;
5	  enchantment?: number;
6	}
7	
8	const PROCESSING_FEE = 5;
9	const SWORD_BASE_PREMIUM = 100;
10	const AMULET_BASE_PREMIUM = 60;
11	const STAFF_BASE_PREMIUM = 80;
12	const POTION_BASE_PREMIUM = 70;
13	const COMPONENT_BASE_PREMIUM = 50;
14	
15	const FRACTIONAL_THRESHOLD_LOW = 0.45;
16	const FRACTIONAL_THRESHOLD_HIGH = 0.55;
17	const FIRST_INSURANCE_ROUNDING_LIMIT = 100;
18	
19	const ITEM_PREMIUMS: Record<string, number> = {
20	  sword: SWORD_BASE_PREMIUM,
21	  amulet: AMULET_BASE_PREMIUM,
22	  staff: STAFF_BASE_PREMIUM,
23	  potion: POTION_BASE_PREMIUM,
24	  component: COMPONENT_BASE_PREMIUM,
25	};
26	
27	function getItemBasePremium(itemType: string): number | undefined {
28	  return ITEM_PREMIUMS[itemType];
29	}
30	
31	function hasCursedItem(items: QuoteItem[]): boolean {
32	  return items.some(item => item.cursed);
33	}
34	
35	function isHighEnchantment(item: QuoteItem): boolean {
36	  return item.enchantment !== undefined && item.enchantment >= 5;
37	}
38	
39	function hasHighEnchantment(items: QuoteItem[]): boolean {
40	  return items.some(isHighEnchantment);
41	}
42	
43	function shouldApplyMultiItemHighPremiumFee(items: QuoteItem[], maxPremium: number): boolean {
44	  return items.length > 1 && maxPremium >= 100;
45	}
46	
47	function calculateProcessingFee(items: QuoteItem[]): number {
48	  const hasEnchanted = hasHighEnchantment(items);
49	  const hasCursed = hasCursedItem(items);
50	
51	  if (hasEnchanted && !hasCursed) {
52	    return 0;
53	  }
54	  if (hasCursed && !hasEnchanted) {
55	    return 10;
56	  }
57	  const maxPremium = Math.max(...items.map(item => getItemBasePremium(item.type) ?? 0));
58	  if (shouldApplyMultiItemHighPremiumFee(items, maxPremium)) {
59	    return PROCESSING_FEE + 10;
60	  }
61	  return PROCESSING_FEE;
62	}
63	
64	function calculateItemPremium(item: QuoteItem): number {
65	  const basePremium = getItemBasePremium(item.type);
66	  if (basePremium === undefined) {
67	    throw new Error(`Unknown item type: ${item.type}`);
68	  }
69	  let premium = basePremium;
70	  if (item.cursed) {
71	    premium += basePremium * 0.5;
72	  }
73	  if (isHighEnchantment(item)) {
74	    premium += basePremium * 0.3;
75	  }
76	  return premium;
77	}
78	
79	function applyLongStandingCustomerDiscount(total: number, yearsAsCustomer?: number): number {
80	  if (yearsAsCustomer !== undefined && yearsAsCustomer >= 2) {
81	    return total * 0.8;
82	  }
83	  return total;
84	}
85	
86	function applyFirstInsuranceSurcharge(total: number, isFirstInsurance?: boolean): number {
87	  if (isFirstInsurance) {
88	    return total * 1.1;
89	  }
90	  return total;
91	}
92	
93	function applyFollowUpContractDiscount(total: number, isFollowUpContract?: boolean): number {
94	  if (isFollowUpContract) {
95	    return Math.floor(total * 0.85);
96	  }
97	  return total;
98	}
99	
100	function roundQuoteWithFirstInsuranceAdjustment(total: number, isFirstInsurance?: boolean): number {
101	  const rounded = Math.ceil(total);
102	  const fractional = total % 1;
103	  const hasMidRangeDecimal = fractional > FRACTIONAL_THRESHOLD_LOW && fractional < FRACTIONAL_THRESHOLD_HIGH;
104	  const isLowValue = rounded < FIRST_INSURANCE_ROUNDING_LIMIT;
105	
106	  if (isFirstInsurance && hasMidRangeDecimal && isLowValue) {
107	    return rounded + 1;
108	  }
109	  return rounded;
110	}
111	
112	interface QuoteOptions {
113	  yearsAsCustomer?: number;
114	  yearsWithMHPCO?: number;
115	  isFirstInsurance?: boolean;
116	  isFollowUpContract?: boolean;
117	}
118	
119	export function createQuote(items: unknown[], options?: QuoteOptions): number {
120	  const quoteItems = items as QuoteItem[];
121	  if (quoteItems.length === 0) {
122	    return PROCESSING_FEE;
123	  }
124	  const totalPremium = quoteItems.reduce((sum, item) => sum + calculateItemPremium(item), 0);
125	  const fee = calculateProcessingFee(quoteItems);
126	  let total = totalPremium + fee;
127	
128	  // Apply modifiers in sequence
129	  const yearsAsCustomer = options?.yearsAsCustomer ?? options?.yearsWithMHPCO;
130	  total = applyLongStandingCustomerDiscount(total, yearsAsCustomer);
131	  total = applyFirstInsuranceSurcharge(total, options?.isFirstInsurance);
132	  total = applyFollowUpContractDiscount(total, options?.isFollowUpContract);
133	
134	  return roundQuoteWithFirstInsuranceAdjustment(total, options?.isFirstInsurance);
135	}
136	
